function greet() {
  console.log('Hello, world!');
}
greet();

function greetPerson(name) {
  console.log('Hello, ' + name + '!');
}
greetPerson('Alice');

function add(a, b) {
  return a + b;
}
const sum = add(5, 3);
console.log(sum); // Outputs: 8

// Example causing an Uncaught TypeError
let person = null;

// Trying to access a property of null
console.log(person.name);

// Fix: make sure person is not null before accessing 'name'
if (person !== null) {
  console.log(person.name);
} else {
  console.log('person is null, cannot access name.');
}

let age: number = 25;
let name: string = "Alice";

// This will cause an error:
age = "twenty-five";  // Error: Type 'string' is not assignable to type 'number'.

let myFunc: (() => void) | undefined;

myFunc(); // Error: undefined is not a function

// Fix by assigning a function before calling
myFunc = () => {
  console.log('Hello, world!');
};
myFunc(); // Works fine

